SELECT COUNT(event_id) AS event_count
FROM disaster_events
WHERE location = 'Miami';

SELECT peril_name
FROM perils
WHERE severity = 'high';

SELECT peril_name, COUNT(peril_id) AS peril_count
FROM perils
GROUP BY peril_name;

SELECT peril_name
FROM perils
WHERE peril_id = '0';

SELECT location
  FROM disaster_events
  WHERE peril_id = '0';

SELECT MAX(intensity) AS max_intensity
FROM disaster_events
WHERE location = 'Miami';

SELECT AVG(estimated_cost) AS avg_estimated_cost
FROM response_actions
WHERE event_id = 1;

SELECT DISTINCT year
FROM historical_data
ORDER BY year;
